  it('keeps production renderer app code off legacy business globals', () => {
    const rendererRoot = path.resolve(__dirname, '../../src/renderer/src')
    const sources: Array<{ file: string; source: string }> = []

    const visit = (directory: string): void => {
      for (const entry of fs.readdirSync(directory, { withFileTypes: true })) {
        const absolutePath = path.join(directory, entry.name)
        if (entry.isDirectory()) {
          if (entry.name === '__tests__') continue
          visit(absolutePath)
          continue
        }
        if (!/\.(ts|tsx)$/.test(entry.name) || /\.test\.(ts|tsx)$/.test(entry.name)) continue
        sources.push({
          file: path.relative(rendererRoot, absolutePath),
          source: fs.readFileSync(absolutePath, 'utf-8')
        })
      }
    }

    visit(rendererRoot)

    const legacyReferences = sources.flatMap(({ file, source }) => {
      const matches = [
        ...source.matchAll(/\bwindow\.db\b/g),
        ...source.matchAll(/\bwindow\.[A-Za-z0-9_]*Ops\b/g)
      ]
      return matches.map((match) => `${file}:${match.index ?? 0}:${match[0]}`)
    })

    expect(legacyReferences).toEqual([])
    expect(sources.some(({ source }) => source.includes('window.desktopBridge'))).toBe(true)
  })

