  it('keeps service-level BrowserWindow usage limited to native window ownership', () => {
    const serviceDir = path.resolve(__dirname, '../../src/main/services')
    const serviceSources = fs
      .readdirSync(serviceDir)
      .filter((fileName) => fileName.endsWith('.ts') && !fileName.endsWith('.test.ts'))
      .map((fileName) => ({
        fileName,
        source: fs.readFileSync(path.join(serviceDir, fileName), 'utf-8')
      }))

    const sourcesWithBrowserWindow = serviceSources
      .filter(({ source }) => source.includes('BrowserWindow'))
      .map(({ fileName }) => fileName)
      .sort()

    expect(sourcesWithBrowserWindow).toEqual(['ghostty-service.ts', 'pet-window.ts'])

    for (const { source } of serviceSources) {
      expect(source).not.toContain('webContents.send')
      expect(source).not.toContain('mainWindow.webContents.send')
    }

    const eventPublisherFiles = [
      'app-events.ts',
      'edit-events.ts',
      'git-events.ts',
      'menu-events.ts',
      'notification-events.ts',
      'pet-events.ts',
      'settings-events.ts',
      'shortcut-events.ts',
      'updater-events.ts',
      'worktree-events.ts'
    ]

    for (const fileName of eventPublisherFiles) {
      const source = fs.readFileSync(path.join(serviceDir, fileName), 'utf-8')
      expect(source).toContain('publishDesktopBackendEvent')
      expect(source).not.toContain('BrowserWindow')
      expect(source).not.toContain('webContents.send')
    }

    const ghosttySource = fs.readFileSync(path.join(serviceDir, 'ghostty-service.ts'), 'utf-8')
    const petWindowSource = fs.readFileSync(path.join(serviceDir, 'pet-window.ts'), 'utf-8')

    expect(ghosttySource).toContain('getNativeWindowHandle()')
    expect(ghosttySource).not.toContain('publishDesktopBackendEvent')
    expect(ghosttySource).not.toContain('webContents.send')
    expect(petWindowSource).toContain('new BrowserWindow({')
    expect(petWindowSource).toContain('emitPetStatus(payload)')
    expect(petWindowSource).not.toContain('publishDesktopBackendEvent')
    expect(petWindowSource).not.toContain('webContents.send')
  })

